messages.content:
{
  "root_causes": [
    {
      "type": "Configuration error (DHCP default gateway)",
      "cause": "R2's DHCP pool for 172.16.0.0/24 advertises the wrong default gateway (192.168.0.1). If the server 172.16.0.12 is DHCP-assigned it would receive an incorrect gateway and send replies out via 192.168.0.1 instead of R2, causing pings from the monitoring host to fail (asymmetric/misrouted return path).",
      "evidence": [
        "R2 DHCP pool R2_LAN: network 172.16.0.0/24 (mask 255.255.255.0) (get_dhcp_config:router2)",
        "R2 DHCP pool R2_LAN: default-router list contains \"192.168.0.1\" (get_dhcp_config:router2)",
        "R2 GigabitEthernet0/0/0 IP 172.16.0.1/24 (R2 LAN gateway) (get_running_config:router2)",
